INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605103A$$, 2026, $$This Program Element funds the RAND-Arroyo Center, the Department of the Army's Federally Funded Research and Development Center, for strategic studies and
analysis. The Army's management of RAND-Arroyo's activities are governed by AR 5-21. RAND-Arroyo Center provides strategic analytical research across a broad
spectrum of issues grouped into the following core competencies research areas: Personnel, Training, and Health; Forces and Logistics; and Strategy, Doctrine and
Resources; applied national security knowledge; academic rigor; multidisciplinary teams; and dynamism, which includes innovation and agility. The RAND-Arroyo
Center research agenda is primarily focused on mid/long-term strategic concerns. Current priorities include: implementation of the National Defense Strategy; total force
readiness; Army modernization; operations and dynamic force employment; reform of business processes; multi-domain operations; soldier-centric investments; and
soldier and family resilience. Results and analytical findings directly affect senior leadership deliberations on major issues. The Arroyo Center Policy Committee (ACPC),
is co-chaired by the Under Secretary of the Army and Vice Chief of Staff of the Army, provides guidance, sets the annual research plan, and monitors execution. RAND-
Arroyo research is sponsored by Army Senior Leaders and Army Major Commands. In FY21, the ACPC 1) directed a change in the execution of the RAND-Arroyo
program which resulted in a change to the business model and 2) directed a consolidation of existing resources for the RAND-Arroyo program.$$, $$This Program Element funds the RAND-Arroyo Center, the Department of the Army's Federally Funded Research and Development Center, for strategic studies and
analysis. The Army's management of RAND-Arroyo's activities are governed by AR 5-21. RAND-Arroyo Center provides strategic analytical research across a broad
spectrum of issues grouped into the following core competencies research areas: Personnel, Training, and Health; Forces and Logistics; and Strategy, Doctrine and
Resources; applied national security knowledge; academic rigor; multidisciplinary teams; and dynamism, which includes innovation and agility. The RAND-Arroyo
Center research agenda is primarily focused on mid/long-term strategic concerns. Current priorities include: implementation of the National Defense Strategy; total force
readiness; Army modernization; operations and dynamic force employment; reform of business processes; multi-domain operations; soldier-centric investments; and
soldier and family resilience. Results and analytical findings directly affect senior leadership deliberations on major issues. The Arroyo Center Policy Committee (ACPC),
is co-chaired by the Under Secretary of the Army and Vice Chief of Staff of the Army, provides guidance, sets the annual research plan, and monitors execution. RAND-
