INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0603461A$$, 2027, $$The High Performance Computing Modernization Program (HPCMP) addresses the supercomputing requirements of DoW scientists and engineers by: (1)
demonstrating and maturing the most advanced, leading-edge computational architectures while exploiting the resulting systems by employing complementary
specialized expertise; (2) demonstrating and maturing the Defense Research and Engineering Network (DREN), which investigates, demonstrates, and matures
leading-edge digital networking and security technologies to securely deliver computational capabilities to the distributed DoW RDT& community; and (3) leveraging
specialized expertise from DoW, other federal departments and agencies, industry, and academia to demonstrate and mature leading-edge software application codes.
DoW Supercomputing Resource Centers (DSRCs) provide extensive computational capabilities to demonstrate and mature emerging technologies that address the
supercomputing requirements of the DoW RDTE community in the areas of hardware, software, and programming environments. All HPCMP sites are interconnected
to each other, the DoW High Performance Computing (HPC) RDTE community, and other major defense sites via the DREN, a research network which investigates,
demonstrates, and matures (a) state-of-the-art digital networking technologies to ensure a robust distributed environment and (b) the most advanced digital security
capabilities to protect the intellectual property of the DoW and its contract entities as they employ HPCMP capabilities. The HPCMP's software application effort (a)
optimizes, enhances, demonstrates, and matures critical DoW physics-based and engineering software to allow scientists and engineers to execute calculations with
precision and efficiency on leading-edge supercomputers, (b) demonstrates and matures immersive collaborative programming environments to improve science and
engineering workflows, and (c) demonstrates and matures leading-edge computational technology from academia and industry. These synergistic activities collectively
demonstrate and mature horizontal technologies that are exploited across the DoW RDTE community, ensuring the DoW maintains the most advanced research and
development ecosystem in computationally intensive modeling and design.

 The research cited is consistent with the Under Secretary of War for Research and Engineering priority focus areas and the Army Modernization Strategy.
